"use client";

import { type RefObject, useEffect, useRef } from "react";
import {
  composedContains,
  getComposedEventTarget,
  getDeepActiveElement,
  isHTMLElement,
  isHTMLInputElement,
} from "./utils/element-guards";
import { restoreFocus as restoreFocusTarget } from "./utils/focus-restore";
import {
  documentOrder,
  getComposedChildren,
  getFocusableElements,
  getTabbableElements,
  isFocusable,
} from "./utils/focusable";
import { useFocusRestore } from "./use-focus-restore";

/** Options for trapping Tab focus inside a container. */
export interface UseFocusTrapOptions {
  /** Element that receives focus when the trap activates. */
  initialFocus?: RefObject<HTMLElement | null>;
  /** Restore focus to the previously focused element when the trap releases. */
  restoreFocus?: boolean;
  /** Whether the focus trap is active. */
  enabled?: boolean;
}

interface TrapEntry {
  container: HTMLElement;
  ownerDocument: Document;
  initialFocus: RefObject<HTMLElement | null> | undefined;
  lastFocused: HTMLElement;
  handleKeyDown: (event: KeyboardEvent) => void;
  handleFocusIn: (event: FocusEvent) => void;
  observer: MutationObserver;
  observedTargets: Set<Node>;
  suspended: boolean;
}

interface ActiveTrap {
  container: HTMLElement;
  restoreFocus: boolean;
  release: () => void;
}

// Per-document trap stacks: only the top entry captures focus.
const trapStacks = new WeakMap<Document, TrapEntry[]>();

const TRAP_MUTATION_OPTIONS = {
  childList: true,
  subtree: true,
  attributes: true,
  attributeFilter: [
    "disabled",
    "hidden",
    "open",
    "tabindex",
    "aria-hidden",
    "inert",
    "style",
    "class",
  ],
} as const satisfies MutationObserverInit;

function getOpenShadowRoots(container: HTMLElement): ShadowRoot[] {
  const roots: ShadowRoot[] = [];
  const visit = (element: Element) => {
    if (element.shadowRoot) roots.push(element.shadowRoot);
    for (const child of getComposedChildren(element)) visit(child);
  };
  visit(container);
  return roots;
}

function observeNewTrapTargets(entry: TrapEntry): void {
  const targets: Node[] = [entry.container, ...getOpenShadowRoots(entry.container)];
  for (const target of targets) {
    if (entry.observedTargets.has(target)) continue;
    entry.observer.observe(target, TRAP_MUTATION_OPTIONS);
    entry.observedTargets.add(target);
  }
}

function disconnectTrapObserver(entry: TrapEntry): void {
  entry.observer.disconnect();
  entry.observedTargets.clear();
}

function getTrapStack(ownerDocument: Document): TrapEntry[] {
  let stack = trapStacks.get(ownerDocument);
  if (!stack) {
    stack = [];
    trapStacks.set(ownerDocument, stack);
  }
  return stack;
}

function armEntry(entry: TrapEntry): void {
  if (!entry.suspended) return;
  entry.ownerDocument.addEventListener("keydown", entry.handleKeyDown, true);
  entry.ownerDocument.addEventListener("focusin", entry.handleFocusIn, true);
  observeNewTrapTargets(entry);
  entry.suspended = false;
}

function suspendEntry(entry: TrapEntry): void {
  if (entry.suspended) return;
  entry.ownerDocument.removeEventListener("keydown", entry.handleKeyDown, true);
  entry.ownerDocument.removeEventListener("focusin", entry.handleFocusIn, true);
  disconnectTrapObserver(entry);
  entry.suspended = true;
}

function resumeEntry(entry: TrapEntry): void {
  armEntry(entry);
  const target =
    composedContains(entry.container, entry.lastFocused) &&
    entry.lastFocused.isConnected &&
    isFocusable(entry.lastFocused)
      ? entry.lastFocused
      : pickInitialTarget(entry.container, entry.initialFocus);
  target.focus();
}

function shouldInsertBefore(incoming: TrapEntry, existing: TrapEntry): boolean {
  // Splice an incoming ancestor before its existing descendant so the descendant
  // stays on top; otherwise activation order makes the new trap the top.
  return (
    incoming.container !== existing.container &&
    composedContains(incoming.container, existing.container)
  );
}

function pushTrap(entry: TrapEntry): boolean {
  const stack = getTrapStack(entry.ownerDocument);
  const previousTop = stack.at(-1);
  const insertIndex = stack.findIndex((existing) => shouldInsertBefore(entry, existing));
  if (insertIndex === -1) stack.push(entry);
  else stack.splice(insertIndex, 0, entry);

  const nextTop = stack.at(-1);
  if (previousTop && previousTop !== nextTop) suspendEntry(previousTop);
  return nextTop === entry;
}

function removeTrap(entry: TrapEntry): void {
  const stack = getTrapStack(entry.ownerDocument);
  const index = stack.indexOf(entry);
  if (index < 0) return;
  const wasTop = index === stack.length - 1;
  stack.splice(index, 1);
  if (wasTop) {
    const newTop = stack.at(-1);
    if (newTop) resumeEntry(newTop);
  }
}

function pickInitialTarget(
  container: HTMLElement,
  initialFocus: RefObject<HTMLElement | null> | undefined,
): HTMLElement {
  const requested = initialFocus?.current;
  if (requested && composedContains(container, requested) && isFocusable(requested))
    return requested;
  return getFocusableElements(container)[0] ?? container;
}

function isInsideContainer(
  container: HTMLElement,
  target: EventTarget | null,
): target is HTMLElement {
  return isHTMLElement(target) && composedContains(container, target);
}

function getTabbableFromAnchor(
  tabbableEls: [HTMLElement, ...HTMLElement[]],
  activeElement: HTMLElement,
  shiftKey: boolean,
): HTMLElement {
  const firstTabbable = tabbableEls[0];
  const documentOrderEls = [...tabbableEls].sort(documentOrder);
  if (shiftKey) {
    for (let index = documentOrderEls.length - 1; index >= 0; index -= 1) {
      const candidate = documentOrderEls[index];
      if (candidate && documentOrder(candidate, activeElement) < 0) return candidate;
    }
    return documentOrderEls.at(-1) ?? firstTabbable;
  }

  for (const candidate of documentOrderEls) {
    if (documentOrder(activeElement, candidate) < 0) return candidate;
  }
  return documentOrderEls[0] ?? firstTabbable;
}

function hasExcludedCheckedRadioPeer(container: HTMLElement, element: HTMLElement): boolean {
  if (!isHTMLInputElement(element) || element.type !== "radio" || element.name === "") return false;
  const root = element.getRootNode();
  return getFocusableElements(container).some(
    (candidate) =>
      candidate !== element &&
      isHTMLInputElement(candidate) &&
      candidate.type === "radio" &&
      candidate.name === element.name &&
      candidate.form === element.form &&
      candidate.getRootNode() === root &&
      candidate.checked &&
      candidate.tabIndex < 0,
  );
}

/**
 * Keeps Tab and Shift+Tab focus inside a container while active, with nested
 * trap stacking and optional focus restoration on release. Active traps listen
 * for keydown and focusin in the capture phase on the container's owner document.
 */
export function useFocusTrap(
  containerRef: RefObject<HTMLElement | null>,
  options: UseFocusTrapOptions = {},
): void {
  const { initialFocus, restoreFocus = true, enabled = true } = options;
  const activeTrapRef = useRef<ActiveTrap | null>(null);
  const trapEntryRef = useRef<TrapEntry | null>(null);
  // Detach listeners BEFORE focus moves out in release(), or the document-level
  // focusin recapture re-traps the restored target. restoreOnUnmount:false keeps
  // this stack hook from moving focus during its own unmount cleanup.
  const { capture, restore } = useFocusRestore({
    enabled: restoreFocus,
    restoreOnUnmount: false,
  });

  // No dependency array on purpose: React does not re-fire effects when
  // containerRef.current mutates while the ref object stays stable.
  useEffect(() => {
    const nextContainer = enabled ? containerRef.current : null;
    const active = activeTrapRef.current;
    if (active && active.container === nextContainer) {
      // restoreFocus is release-time policy; update in place instead of tearing
      // down (which would recapture the interior as the restore target, not the opener).
      active.restoreFocus = restoreFocus;
      return;
    }

    active?.release();
    activeTrapRef.current = null;

    if (!nextContainer) return;
    const container = nextContainer;
    const ownerDocument = container.ownerDocument;
    // Resolve the observer BEFORE any side effect (focus capture, tabindex mutation)
    // so a document without MutationObserver bails out leaving the container untouched.
    const MutationObserverCtor = ownerDocument.defaultView?.MutationObserver;
    if (typeof MutationObserverCtor !== "function") return;
    // Capture the opener before focus moves inside, so a false-to-true toggle can still restore to it.
    const activeAtActivation = getDeepActiveElement(ownerDocument);
    const opener =
      isHTMLElement(activeAtActivation) && !isInsideContainer(container, activeAtActivation)
        ? activeAtActivation
        : null;
    const restoreTarget = capture(ownerDocument);

    const hadTabIndex = container.hasAttribute("tabindex");
    const originalTabIndex = container.getAttribute("tabindex");
    if (!hadTabIndex) container.setAttribute("tabindex", "-1");

    let lastFocused: HTMLElement = container;

    const recapture = () => {
      const target =
        composedContains(container, lastFocused) &&
        lastFocused.isConnected &&
        isFocusable(lastFocused)
          ? lastFocused
          : pickInitialTarget(container, initialFocus);
      target.focus();
    };

    const handleFocusIn = (event: FocusEvent) => {
      const target = getComposedEventTarget(event);
      if (isInsideContainer(container, target)) {
        lastFocused = target;
        const entry = trapEntryRef.current;
        if (entry) {
          entry.lastFocused = target;
          if (!entry.suspended) observeNewTrapTargets(entry);
        }
        return;
      }
      recapture();
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key !== "Tab") return;

      const entry = trapEntryRef.current;
      if (entry && !entry.suspended) observeNewTrapTargets(entry);
      const focusableEls = getTabbableElements(container);
      if (focusableEls.length === 0) {
        event.preventDefault();
        if (getDeepActiveElement(ownerDocument) !== container) container.focus();
        return;
      }

      const first = focusableEls[0];
      const last = focusableEls[focusableEls.length - 1];
      const activeElement = getDeepActiveElement(ownerDocument);

      if (!isInsideContainer(container, activeElement)) {
        event.preventDefault();
        (event.shiftKey ? last : first)?.focus();
        return;
      }

      if (!focusableEls.includes(activeElement)) {
        event.preventDefault();
        getTabbableFromAnchor(
          focusableEls as [HTMLElement, ...HTMLElement[]],
          activeElement,
          event.shiftKey,
        ).focus();
        return;
      }

      const activeIndex = focusableEls.indexOf(activeElement);
      const adjacent = focusableEls[activeIndex + (event.shiftKey ? -1 : 1)];
      if (adjacent && hasExcludedCheckedRadioPeer(container, adjacent)) {
        event.preventDefault();
        adjacent.focus();
        return;
      }

      if (event.shiftKey) {
        if (activeElement === first) {
          event.preventDefault();
          last?.focus();
        }
      } else {
        if (activeElement === last) {
          event.preventDefault();
          first?.focus();
        }
      }
    };

    const observer = new MutationObserverCtor(() => {
      const entry = trapEntryRef.current;
      if (entry && !entry.suspended) observeNewTrapTargets(entry);
      if (
        lastFocused.isConnected &&
        composedContains(container, lastFocused) &&
        isFocusable(lastFocused)
      )
        return;
      recapture();
    });

    // Push BEFORE arming/focusing: pushTrap suspends the previous top so its
    // focusin handler does not recapture focus away from this new trap.
    const entry: TrapEntry = {
      container,
      ownerDocument,
      initialFocus,
      lastFocused,
      handleKeyDown,
      handleFocusIn,
      observer,
      observedTargets: new Set(),
      suspended: true,
    };
    trapEntryRef.current = entry;
    const isTopTrap = pushTrap(entry);

    if (isTopTrap) {
      armEntry(entry);
      if (!isInsideContainer(container, getDeepActiveElement(ownerDocument))) {
        pickInitialTarget(container, initialFocus).focus();
      }
      const activeElement = getDeepActiveElement(ownerDocument);
      lastFocused = isInsideContainer(container, activeElement)
        ? activeElement
        : pickInitialTarget(container, initialFocus);
      entry.lastFocused = lastFocused;
    } else {
      const activeElement = getDeepActiveElement(ownerDocument);
      if (isInsideContainer(container, activeElement)) {
        lastFocused = activeElement;
        entry.lastFocused = lastFocused;
      }
    }

    const activeTrap: ActiveTrap = {
      container,
      restoreFocus,
      release: () => {
        // Detach own listeners BEFORE removeTrap resumes the outer trap; otherwise
        // our focusin sees the outer trap's refocus as an escape and fights it.
        ownerDocument.removeEventListener("keydown", handleKeyDown, true);
        ownerDocument.removeEventListener("focusin", handleFocusIn, true);
        disconnectTrapObserver(entry);

        removeTrap(entry);
        trapEntryRef.current = null;

        if (!hadTabIndex) {
          container.removeAttribute("tabindex");
        } else if (originalTabIndex !== null) {
          container.setAttribute("tabindex", originalTabIndex);
        }

        if (activeTrap.restoreFocus) {
          const hasOuterTrap = getTrapStack(ownerDocument).length > 0;
          const restored = restore();
          if (!restored && !hasOuterTrap) restoreFocusTarget(restoreTarget ?? opener);
        }
      },
    };
    activeTrapRef.current = activeTrap;
  });

  useEffect(() => {
    return () => {
      const activeTrap = activeTrapRef.current;
      if (!activeTrap) return;
      activeTrapRef.current = null;
      activeTrap.release();
    };
  }, []);
}

"use client";

import { useCallback, useEffect, useEffectEvent, useLayoutEffect, useRef, useState } from "react";
import {
  getDocument,
  getRestorableFocusTarget,
  type RestoreFocusOptions,
  restoreFocus,
} from "./utils/focus-restore";

/** Options for capturing and restoring focus around temporary UI. */
export interface UseFocusRestoreOptions extends RestoreFocusOptions {
  /** Whether capture and restore are active. */
  enabled?: boolean;
  /** Restore focus during cleanup if capture was called and restore was not called manually. */
  restoreOnUnmount?: boolean;
  /** Fallback element to focus when the captured target is unavailable. */
  fallback?: HTMLElement | null;
}

/** Return value from `useFocusRestore`. */
export interface UseFocusRestoreReturn {
  /** Stores the current focus target for the provided document. */
  capture: (ownerDocument?: Document) => HTMLElement | null;
  /** Focuses the captured or fallback target and returns whether focus moved. */
  restore: () => boolean;
  /** The last captured focus target, or null when nothing is captured. */
  target: HTMLElement | null;
}

interface FocusRestoreEntry {
  target: HTMLElement | null;
  fallbackTargets: HTMLElement[];
  ownerDocument: Document;
}

const focusRestoreStacks = new WeakMap<Document, FocusRestoreEntry[]>();

function getFocusRestoreStack(ownerDocument: Document): FocusRestoreEntry[] {
  let stack = focusRestoreStacks.get(ownerDocument);
  if (!stack) {
    stack = [];
    focusRestoreStacks.set(ownerDocument, stack);
  }
  return stack;
}

function removeEntry(entry: FocusRestoreEntry): void {
  const stack = getFocusRestoreStack(entry.ownerDocument);
  const index = stack.lastIndexOf(entry);
  if (index >= 0) stack.splice(index, 1);
}

function resolveOptions(options: UseFocusRestoreOptions): Required<UseFocusRestoreOptions> {
  return {
    enabled: options.enabled ?? true,
    restoreOnUnmount: options.restoreOnUnmount ?? true,
    preventScroll: options.preventScroll ?? false,
    fallback: options.fallback ?? null,
  };
}

function releaseEntry(
  entry: FocusRestoreEntry,
  shouldRestore: boolean,
  options: Required<UseFocusRestoreOptions>,
): boolean {
  const stack = getFocusRestoreStack(entry.ownerDocument);
  const index = stack.lastIndexOf(entry);
  if (index < 0) return false;

  const isTopEntry = index === stack.length - 1;
  stack.splice(index, 1);

  if (!shouldRestore || !options.enabled) return false;

  const candidates = [entry.target, ...entry.fallbackTargets].filter(
    (candidate): candidate is HTMLElement => candidate !== null,
  );
  if (!isTopEntry) {
    for (const entryAbove of stack.slice(index)) {
      entryAbove.fallbackTargets = [
        ...candidates,
        ...entryAbove.fallbackTargets.filter((candidate) => !candidates.includes(candidate)),
      ];
    }
    return false;
  }

  for (const candidate of candidates) {
    if (restoreFocus(candidate, { preventScroll: options.preventScroll })) return true;
  }
  return restoreFocus(options.fallback, { preventScroll: options.preventScroll });
}

/**
 * Captures the current focus target and restores it later, with per-document
 * stack ordering for nested overlays.
 */
export function useFocusRestore(options: UseFocusRestoreOptions = {}): UseFocusRestoreReturn {
  const resolvedOptions = resolveOptions(options);
  const optionsRef = useRef(resolvedOptions);
  const entryRef = useRef<FocusRestoreEntry | null>(null);
  const [target, setTarget] = useState<HTMLElement | null>(null);

  const teardown = useEffectEvent(
    (shouldRestore: boolean, options: Required<UseFocusRestoreOptions>) => {
      const entry = entryRef.current;
      if (!entry) return;

      entryRef.current = null;
      releaseEntry(entry, shouldRestore, options);
      setTarget(null);
    },
  );

  // Latest-ref sync: stable focus callbacks read optionsRef, so it must update every render by design.
  useLayoutEffect(() => {
    optionsRef.current = resolvedOptions;
  });

  const capture = useCallback((ownerDocument?: Document) => {
    const resolvedOptions = optionsRef.current;
    const doc = ownerDocument ?? resolvedOptions.fallback?.ownerDocument ?? getDocument();
    if (!resolvedOptions.enabled || !doc) {
      const entry = entryRef.current;
      if (entry) {
        entryRef.current = null;
        removeEntry(entry);
      }
      setTarget(null);
      return null;
    }

    const nextTarget = getRestorableFocusTarget(doc) ?? resolvedOptions.fallback;
    const entry = entryRef.current ?? { target: null, fallbackTargets: [], ownerDocument: doc };

    removeEntry(entry);
    entry.target = nextTarget;
    entry.fallbackTargets = [];
    entry.ownerDocument = doc;
    entryRef.current = entry;
    getFocusRestoreStack(doc).push(entry);
    setTarget(nextTarget);

    return nextTarget;
  }, []);

  const restore = useCallback(() => {
    const resolvedOptions = optionsRef.current;
    const entry = entryRef.current;

    if (!entry) {
      return resolvedOptions.enabled
        ? restoreFocus(resolvedOptions.fallback, { preventScroll: resolvedOptions.preventScroll })
        : false;
    }

    entryRef.current = null;
    const restored = releaseEntry(entry, true, resolvedOptions);
    setTarget(null);
    return restored;
  }, []);

  useEffect(() => {
    if (resolvedOptions.enabled) return;

    teardown(false, optionsRef.current);
  }, [resolvedOptions.enabled]);

  useEffect(() => {
    return () => {
      teardown(optionsRef.current.restoreOnUnmount, optionsRef.current);
    };
  }, []);

  return { capture, restore, target };
}

import { getDeepActiveElement, isHTMLElement } from "./element-guards";

/** Options shared by the imperative focus-restore utilities. */
export interface RestoreFocusOptions {
  /** Passes `preventScroll` to the focus call when restoring focus. */
  preventScroll?: boolean;
}

export function getDocument(): Document | null {
  return typeof document === "undefined" ? null : document;
}

/**
 * Returns the current restorable focus target, ignoring body, documentElement,
 * disconnected nodes, and missing DOM.
 */
export function getRestorableFocusTarget(ownerDocument?: Document): HTMLElement | null {
  const doc = ownerDocument ?? getDocument();
  if (!doc) return null;

  const activeElement = getDeepActiveElement(doc);
  if (!isHTMLElement(activeElement)) return null;
  if (activeElement === doc.body || activeElement === doc.documentElement) return null;
  if (!activeElement.isConnected) return null;

  return activeElement;
}

/**
 * Focuses a connected target and returns whether the document's active element
 * moved to it.
 */
export function restoreFocus(
  target: HTMLElement | null,
  options: RestoreFocusOptions = {},
): boolean {
  if (!target?.isConnected) return false;

  // Older engines / some jsdom versions reject the FocusOptions argument; fall back to plain focus().
  try {
    target.focus({ preventScroll: options.preventScroll });
  } catch {
    target.focus();
  }

  return getDeepActiveElement(target.ownerDocument) === target;
}

import {
  composedClosest,
  composedContains,
  getDeepActiveElement,
  getShadowHost,
  isHTMLElement,
  isHTMLInputElement,
} from "./element-guards";

const FOCUSABLE_SELECTOR = [
  "a[href]",
  "area[href]",
  "button:not([disabled])",
  'input:not([type="hidden"]):not([disabled])',
  "select:not([disabled])",
  "textarea:not([disabled])",
  "iframe",
  "object",
  "embed",
  "audio[controls]",
  "video[controls]",
  '[contenteditable]:not([contenteditable="false"])',
  "details > summary:first-of-type",
  "[tabindex]:not([disabled])",
].join(",");

function getComposedParentElement(element: Element): Element | null {
  return element.assignedSlot ?? element.parentElement ?? getShadowHost(element);
}

export function getComposedChildren(element: Element): Element[] {
  if (element.shadowRoot) return Array.from(element.shadowRoot.children);
  if (element.localName === "slot") {
    const assigned = (element as HTMLSlotElement).assignedElements({ flatten: true });
    if (assigned.length > 0) return assigned;
  }
  return Array.from(element.children);
}

function isHidden(element: HTMLElement): boolean {
  const elementVisibility = element.ownerDocument.defaultView?.getComputedStyle(element).visibility;
  if (elementVisibility === "hidden" || elementVisibility === "collapse") return true;

  let current: Element | null = element;
  while (current) {
    const style = current.ownerDocument.defaultView?.getComputedStyle(current);
    if (
      current.getAttribute("hidden") === "until-found" ||
      style?.display === "none" ||
      style?.getPropertyValue("content-visibility") === "hidden"
    ) {
      return true;
    }
    current = getComposedParentElement(current);
  }
  return false;
}

function isInert(element: HTMLElement): boolean {
  return composedClosest(element, "[inert]") !== null;
}

function isAriaHidden(element: HTMLElement): boolean {
  // Per ARIA, aria-hidden="false" does NOT re-expose content hidden by an aria-hidden="true" ancestor.
  return composedClosest(element, '[aria-hidden="true"]') !== null;
}

function isHiddenByClosedDetails(element: HTMLElement): boolean {
  let current = getComposedParentElement(element);

  while (current) {
    if (current.localName === "details" && !current.hasAttribute("open")) {
      const firstSummary = Array.from(current.children).find(
        (child) => child.localName === "summary",
      );
      if (!firstSummary || !composedContains(firstSummary, element)) return true;
    }
    current = getComposedParentElement(current);
  }

  return false;
}

/**
 * Returns false when a hidden, inert, or aria-hidden="true" self-or-ancestor
 * (across shadow boundaries) removes the element from keyboard reach. Shared
 * with navigation discovery so it skips the same unreachable items focus does.
 */
export function isReachable(element: HTMLElement): boolean {
  return (
    !isHidden(element) &&
    !isInert(element) &&
    !isAriaHidden(element) &&
    !isHiddenByClosedDetails(element)
  );
}

export function isInsideDisabledFieldset(element: HTMLElement): boolean {
  let fieldset = element.closest<HTMLFieldSetElement>("fieldset[disabled]");
  while (fieldset) {
    const legend = fieldset.querySelector(":scope > legend");
    if (legend?.contains(element)) {
      // Descendants of the first <legend> are not disabled per spec; keep searching upward.
      fieldset = fieldset.parentElement?.closest<HTMLFieldSetElement>("fieldset[disabled]") ?? null;
      continue;
    }
    return true;
  }
  return false;
}

/**
 * Returns true for visible, non-disabled elements that can receive programmatic
 * focus, including `tabIndex={-1}` targets.
 */
export function isFocusable(element: HTMLElement | null): boolean {
  if (!isHTMLElement(element)) return false;
  if (!element.matches(FOCUSABLE_SELECTOR)) return false;
  if (!isReachable(element)) return false;
  if (isInsideDisabledFieldset(element)) return false;
  return true;
}

// jsdom returns compound-selector matches out of tree order; normalize.
const DOCUMENT_POSITION_PRECEDING = 0x02;
const DOCUMENT_POSITION_FOLLOWING = 0x04;

function nativeDocumentOrder(a: HTMLElement, b: HTMLElement): number {
  const pos = a.compareDocumentPosition(b);
  if (pos & DOCUMENT_POSITION_FOLLOWING) return -1;
  if (pos & DOCUMENT_POSITION_PRECEDING) return 1;
  return 0;
}

function composedPath(element: HTMLElement): Element[] {
  const path: Element[] = [];
  let current: Element | null = element;
  while (current) {
    path.push(current);
    current = getComposedParentElement(current);
  }
  return path.reverse();
}

/** Sort comparator that returns elements in composed order across open shadow roots. */
export function documentOrder(a: HTMLElement, b: HTMLElement): number {
  if (a === b) return 0;

  const aPath = composedPath(a);
  const bPath = composedPath(b);
  let index = 0;
  while (aPath[index] && aPath[index] === bPath[index]) index += 1;

  if (index === 0) return nativeDocumentOrder(a, b);
  if (index === aPath.length) return -1;
  if (index === bPath.length) return 1;

  const parent = aPath[index - 1];
  const aSibling = aPath[index];
  const bSibling = bPath[index];
  if (!parent || !aSibling || !bSibling) return nativeDocumentOrder(a, b);

  const children = getComposedChildren(parent);
  const aIndex = children.indexOf(aSibling);
  const bIndex = children.indexOf(bSibling);
  return aIndex >= 0 && bIndex >= 0 ? aIndex - bIndex : nativeDocumentOrder(a, b);
}

function getComposedDescendants(container: HTMLElement): HTMLElement[] {
  const matches: HTMLElement[] = [];
  const visit = (element: Element) => {
    if (
      isHTMLElement(element) &&
      element.matches(FOCUSABLE_SELECTOR) &&
      !element.shadowRoot?.delegatesFocus
    ) {
      matches.push(element);
    }
    for (const child of getComposedChildren(element)) visit(child);
  };

  for (const child of getComposedChildren(container)) visit(child);
  return matches;
}

/**
 * Returns all focusable descendants in DOM order, including programmatic focus
 * targets that are not reachable by Tab.
 */
export function getFocusableElements(container: HTMLElement | null): HTMLElement[] {
  if (!container) return [];
  return getComposedDescendants(container).filter((element) => isFocusable(element));
}

function isRadioInput(element: HTMLElement): element is HTMLInputElement {
  return isHTMLInputElement(element) && element.type === "radio";
}

function isRadioGroupTabStop(element: HTMLElement, focusableElements: HTMLElement[]): boolean {
  if (!isRadioInput(element) || element.name === "") return true;
  const root = element.getRootNode();

  const group = focusableElements.filter(
    (candidate) =>
      isRadioInput(candidate) &&
      candidate.name === element.name &&
      candidate.form === element.form &&
      candidate.getRootNode() === root,
  );
  const checked = group.find((candidate) => isRadioInput(candidate) && candidate.checked);
  return element === (checked ?? group[0]);
}

function tabIndexOrder(element: HTMLElement): number {
  return element.tabIndex > 0 ? element.tabIndex : Number.MAX_SAFE_INTEGER;
}

/**
 * Returns browser Tab-order descendants, excluding negative tabindex targets
 * and collapsing native radio groups to one Tab stop.
 */
export function getTabbableElements(container: HTMLElement | null): HTMLElement[] {
  if (!container) return [];
  const focusableElements = getFocusableElements(container).filter(
    (element) => element.tabIndex >= 0,
  );
  return focusableElements
    .map((element, index) => ({ element, index }))
    .filter(({ element }) => isRadioGroupTabStop(element, focusableElements))
    .sort((a, b) => tabIndexOrder(a.element) - tabIndexOrder(b.element) || a.index - b.index)
    .map(({ element }) => element);
}

/** Returns the first focusable descendant in DOM order. */
export function getFirstFocusableElement(container: HTMLElement | null): HTMLElement | null {
  return getFocusableElements(container)[0] ?? null;
}

/** Returns true when the element contains its owner document's deep active element, across shadow roots. */
export function containsActiveElement(element: HTMLElement): boolean {
  const activeElement = getDeepActiveElement(element.ownerDocument);
  return isHTMLElement(activeElement) && composedContains(element, activeElement);
}

/** Returns the `Window` realm for a DOM value, or null for non-DOM values. */
export function getOwnerView(value: unknown): (Window & typeof globalThis) | null {
  const element = value as { ownerDocument?: Document } | null;
  return element?.ownerDocument?.defaultView ?? null;
}

/** Realm-safe HTMLElement guard for elements from iframes or other documents. */
export function isHTMLElement(value: unknown): value is HTMLElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLElement);
}

/** Realm-safe HTMLInputElement guard. */
export function isHTMLInputElement(value: unknown): value is HTMLInputElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLInputElement);
}

/** Realm-safe HTMLTextAreaElement guard. */
export function isHTMLTextAreaElement(value: unknown): value is HTMLTextAreaElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLTextAreaElement);
}

/** Realm-safe Node guard using a known owner window. */
export function isNode(
  value: unknown,
  ownerView: (Window & typeof globalThis) | null,
): value is Node {
  return Boolean(ownerView && value instanceof ownerView.Node);
}

/** Returns the shadow host when a node lives in a shadow root, else null. */
export function getShadowHost(node: Node): Element | null {
  const view = getOwnerView(node);
  const root = node.getRootNode();
  return view && root instanceof view.ShadowRoot ? root.host : null;
}

/** Returns the deepest active element, descending through open shadow roots. */
export function getDeepActiveElement(root: Document | ShadowRoot): Element | null {
  let active = root.activeElement;
  while (active?.shadowRoot?.activeElement) {
    active = active.shadowRoot.activeElement;
  }
  return active;
}

/** Returns true when `container` contains `target` in the composed tree, across shadow boundaries. */
export function composedContains(container: Node, target: Node | null): boolean {
  let node: Node | null = target;
  while (node) {
    if (container.contains(node)) return true;
    node = getShadowHost(node);
  }
  return false;
}

/** Returns the nearest self-or-ancestor matching `selector` in the composed tree, across shadow boundaries. */
export function composedClosest(element: Element, selector: string): Element | null {
  let current: Element | null = element;
  while (current) {
    const match = current.closest(selector);
    if (match) return match;
    current = getShadowHost(current);
  }
  return null;
}

/**
 * Returns the deepest composed event target, past the retargeted shadow host.
 * Empty `composedPath()` (before dispatch) falls back to `event.target`.
 */
export function getComposedEventTarget(event: Event): EventTarget | null {
  return event.composedPath()[0] ?? event.target;
}

/**
 * Returns true for form-like or editable elements that can own keyboard input,
 * including select and non-text input types.
 */
export function isInputElement(target: EventTarget | null): boolean {
  if (!isHTMLElement(target)) return false;
  const tag = target.tagName.toLowerCase();
  return Boolean(
    tag === "input" || tag === "textarea" || tag === "select" || target.isContentEditable,
  );
}

const NON_EDITABLE_INPUT_TYPES = new Set([
  "button",
  "checkbox",
  "color",
  "file",
  "hidden",
  "image",
  "radio",
  "range",
  "reset",
  "submit",
]);

function hasContentEditableAttribute(element: HTMLElement): boolean {
  if (element.isContentEditable) return true;
  const value = element.getAttribute("contenteditable");
  if (value === null) return false;
  return value === "" || value === "true" || value === "plaintext-only";
}

/**
 * Returns true only for enabled text-editable targets that should keep typing
 * keys instead of global shortcuts.
 */
export function isEditableElement(target: EventTarget | null): boolean {
  if (!isHTMLElement(target)) return false;

  if (isHTMLTextAreaElement(target)) {
    return !target.disabled && !target.readOnly;
  }

  if (isHTMLInputElement(target)) {
    if (target.disabled || target.readOnly) return false;
    const type = (target.type || "text").toLowerCase();
    return !NON_EDITABLE_INPUT_TYPES.has(type);
  }

  return hasContentEditableAttribute(target);
}
